mapper.select:
SELECT * FROM ( SELECT seller_name, seller_email_count AS email_count, '' AS inviter_name, '' AS invitee_name, 0 AS seller_type, source, email_account_count, create_time FROM store_seller_email_limit WHERE source=0
and seller_id = #{storeSellerEmailLimit.sellerId}
UNION
SELECT seller_name, seller_email_count, seller_name, invitation_user_name, 1, source, 0, create_time FROM store_seller_email_limit WHERE source=1
and seller_id = #{storeSellerEmailLimit.sellerId}
UNION
SELECT
invitation_user_name, invitation_email_count, seller_name AS inviter_name, invitation_user_name, 2, source, '', create_time FROM store_seller_email_limit WHERE source=1
and invitation_user_id = #{storeSellerEmailLimit.sellerId}
) AS limits WHERE 1=1
and seller_type = #{storeSellerEmailLimit.source}
